window.docContents[74].resolve({"/#Zippers___-A-Documentation-Example":{"contents":"\nHere's an example project showing how to document a Lean package with Verso.\nIt's a good idea to read the document's source together with the rendered output, because it demonstrates how to use various features.\n\nThis document's setup has the following properties:\n\n* It decouples the version of Lean used for Verso from that used by the library. This is important because it allows a library to stay on an older version of Lean while still adopting improvements to Verso that require new compiler versions.* The example code may use any Lean syntax, including custom syntax, and it will be highlighted correctly.* Examples to be included in the documentation are indicated with special comments.\n\nThe library here was chosen to be small.\nIt is not intended as a realistic library, but rather to exercise certain interesting features.\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n","context":"","header":"Zippers: A Documentation Example","id":"/#Zippers___-A-Documentation-Example"}});